#include <stdio.h>
#include <stdlib.h>
typedef struct Node {
    int key;
    int val;
    struct Node* next;
    struct Node* prev;
} Node;
typedef struct {
    Node* head;
    Node* tail;
    int cap;
    Node** m;
} LRUCache;
LRUCache* lRUCacheCreate(int capacity) {
    LRUCache* cache = (LRUCache*) malloc(sizeof(LRUCache));
    cache->head = (Node*) malloc(sizeof(Node));
    cache->tail = (Node*) malloc(sizeof(Node));
    cache->cap = capacity;
    cache->m = (Node**) calloc(capacity, sizeof(Node*));
    cache->head->next = cache->tail;
    cache->tail->prev = cache->head;
    return cache;
}
void lRUCacheFree(LRUCache* obj) {
    free(obj->head);
    free(obj->tail);
    free(obj->m);
    free(obj);
}
int lRUCacheGet(LRUCache* obj, int key) {
    if (obj->m[key] != NULL) {
        Node* node = obj->m[key];
        int val = node->val;
        // Remove node from list
        node->prev->next = node->next;
        node->next->prev = node->prev;
        // Add node to front
        node->next = obj->head->next;
        node->prev = obj->head;
        obj->head->next->prev = node;
        obj->head->next = node;
        return val;
    }
    return -1;
}
void lRUCachePut(LRUCache* obj, int key, int value) {
    if (obj->m[key] != NULL) {
        Node* node = obj->m[key];
        node->val = value;
        // Remove node from list
        node->prev->next = node->next;
        node->next->prev = node->prev;
        // Add node to front
        node->next = obj->head->next;
        node->prev = obj->head;
        obj->head->next->prev = node;
        obj->head->next = node;
    } else {
        Node* node = (Node*) malloc(sizeof(Node));
        node->key = key;
        node->val = value;
        // Add node to front
        node->next = obj->head->next;
        node->prev = obj->head;
        obj->head->next->prev = node;
        obj->head->next = node;
        obj->m[key] = node;
        if (obj->cap == 0) {
            // Remove last node
            Node* last = obj->tail->prev;
            last->prev->next = obj->tail;
            obj->tail->prev = last->prev;
            free(last);
            obj->cap = 1;
        } else {
            obj->cap--;
        }
    }
}

